import Razorpay from 'razorpay';
import crypto from 'crypto';

/**
 * Initialize Razorpay instance with API credentials
 * Credentials should be stored in environment variables
 */
export function initializeRazorpay() {
  const keyId = process.env.RAZORPAY_KEY_ID;
  const keySecret = process.env.RAZORPAY_KEY_SECRET;

  if (!keyId || !keySecret) {
    throw new Error('Razorpay API credentials not configured');
  }

  return new Razorpay({
    key_id: keyId,
    key_secret: keySecret,
  });
}

/**
 * Create a Razorpay order
 */
export async function createRazorpayOrder(options: {
  amount: number; // Amount in paise (1 rupee = 100 paise)
  currency?: string;
  receipt?: string;
  notes?: Record<string, string>;
}) {
  const razorpay = initializeRazorpay();

  const orderOptions = {
    amount: options.amount,
    currency: options.currency || 'INR',
    receipt: options.receipt || `receipt_${Date.now()}`,
    notes: options.notes || {},
  };

  try {
    const order = await razorpay.orders.create(orderOptions);
    return order;
  } catch (error) {
    console.error('Error creating Razorpay order:', error);
    throw error;
  }
}

/**
 * Verify Razorpay payment signature
 * This is critical for security - always verify on the server side
 */
export function verifyRazorpaySignature(
  orderId: string,
  paymentId: string,
  signature: string
): boolean {
  const keySecret = process.env.RAZORPAY_KEY_SECRET;

  if (!keySecret) {
    throw new Error('Razorpay key secret not configured');
  }

  const body = `${orderId}|${paymentId}`;
  const expectedSignature = crypto
    .createHmac('sha256', keySecret)
    .update(body)
    .digest('hex');

  return expectedSignature === signature;
}

/**
 * Fetch payment details from Razorpay
 */
export async function getPaymentDetails(paymentId: string) {
  const razorpay = initializeRazorpay();

  try {
    const payment = await razorpay.payments.fetch(paymentId);
    return payment;
  } catch (error) {
    console.error('Error fetching payment details:', error);
    throw error;
  }
}

