/**
 * Create a recurring payment (subscription) for monthly donations
 */
export async function createSubscription(options: {
  planId: string;
  customerId: string;
  quantity?: number;
  totalCount?: number;
  notes?: Record<string, string>;
}) {
  const razorpay = initializeRazorpay();

  const subscriptionOptions = {
    plan_id: options.planId,
    customer_notify: 1,
    quantity: options.quantity || 1,
    total_count: options.totalCount || 12, // 12 months by default
    notes: options.notes || {},
  };

  try {
    const subscription = await razorpay.subscriptions.create(subscriptionOptions as any);
    return subscription;
  } catch (error) {
    console.error('Error creating subscription:', error);
    throw error;
  }
}

/**
 * Create a plan for recurring donations
 */
export async function createPlan(options: {
  period: 'monthly' | 'yearly';
  interval: number;
  amount: number; // Amount in paise
  currency?: string;
  notes?: Record<string, string>;
}) {
  const razorpay = initializeRazorpay();

  const planOptions = {
    period: options.period,
    interval: options.interval,
    amount: options.amount,
    currency: options.currency || 'INR',
    notes: options.notes || {},
  };

  try {
    const plan = await razorpay.plans.create(planOptions as any);
    return plan;
  } catch (error) {
    console.error('Error creating plan:', error);
    throw error;
  }
}

/**
 * Refund a payment
 */
export async function refundPayment(
  paymentId: string,
  options?: {
    amount?: number; // Amount in paise for partial refund
    notes?: Record<string, string>;
  }
) {
  const razorpay = initializeRazorpay();

  const refundOptions = {
    amount: options?.amount,
    notes: options?.notes,
  };

  try {
    const refund = await razorpay.payments.refund(paymentId, refundOptions);
    return refund;
  } catch (error) {
    console.error('Error refunding payment:', error);
    throw error;
  }
}

/**
 * Format amount from rupees to paise
 */
export function formatAmountToPaise(rupees: number): number {
  return Math.round(rupees * 100);
}

/**
 * Format amount from paise to rupees
 */
export function formatAmountToRupees(paise: number): number {
  return paise / 100;
}

/**
 * Validate donation amount
 */
export function validateDonationAmount(amount: number): {
  valid: boolean;
  error?: string;
} {
  const minAmount = 10; // Minimum ₹10
  const maxAmount = 100000; // Maximum ₹100,000

  if (amount < minAmount) {
    return {
      valid: false,
      error: `Minimum donation amount is ₹${minAmount}`,
    };
  }

  if (amount > maxAmount) {
    return {
      valid: false,
      error: `Maximum donation amount is ₹${maxAmount}`,
    };
  }

  return { valid: true };
}
